<span class="line"><span style="color:#F07178;">  </span><span style="color:#82AAFF;">expect</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">callback</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">not</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">toBeCalled</span><span style="color:#F07178;">()</span><span style="color:#89DDFF;">;</span></span>
