<span class="line"><span style="color:#F07178;">      </span><span style="color:#82AAFF;">infiniteTimerGame</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">callback</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
